// ============================================================================
// VALIDATE & EXTRACT INPUT for QC Chat v2.0
// ============================================================================

const rawInput = $input.first().json;

let input = {};
if (rawInput.body && typeof rawInput.body === 'string') {
  try {
    input = JSON.parse(rawInput.body.trim().replace(/^=/, ''));
  } catch (e) {
    console.log('Failed to parse body:', e.message);
  }
} else if (rawInput.body && typeof rawInput.body === 'object') {
  input = rawInput.body;
} else {
  input = rawInput;
}

console.log('=== QC CHAT v2.0 INPUT ===');
console.log('Message:', (input.message || '').substring(0, 100));
console.log('Context type:', input.context);
console.log('Has qcContext:', !!input.qcContext);
console.log('Has roleContext:', !!input.roleContext);
console.log('Viewer role:', input.viewerRole);

if (!input.message) {
  throw new Error('No message provided');
}

// Pass everything through to the prompt builder
return [{ json: {
  message: input.message,
  contractId: input.contractId || null,
  clauseId: input.clauseId || null,
  clauseName: input.clauseName || null,
  clauseCategory: input.clauseCategory || null,
  touchpointType: input.context || 'qc_chat',
  viewerRole: input.viewerRole || 'initiator',
  roleContext: input.roleContext || null,
  contractTypeKey: input.contractTypeKey || null,
  initiatorPartyRole: input.initiatorPartyRole || null,
  qcContext: input.qcContext || {},
  // Session-based fields (passthrough)
  sessionId: input.sessionId || null,
  providerId: input.providerId || null,
  currentPhase: input.currentPhase || null,
  alignmentScore: input.alignmentScore || null,
  negotiationContext: input.negotiationContext || null,
  dashboardData: input.dashboardData || null,
} }];

// ============================================================================
// EXTRACT PROMPT BUILDER RESPONSE & PREPARE CLAUDE API CALL
// ============================================================================

const promptData = $input.first().json;

console.log('=== PROMPT BUILDER RESPONSE ===');
console.log('System prompt length:', (promptData.systemPrompt || '').length);
console.log('User prompt length:', (promptData.userPrompt || '').length);
console.log('Viewer:', promptData.viewerName, '(' + promptData.userRoleLabel + ')');
console.log('Is drafting:', promptData.isDrafting);

if (!promptData.systemPrompt || !promptData.userPrompt) {
  throw new Error('Prompt builder returned empty prompts');
}

return [{ json: {
  systemPrompt: promptData.systemPrompt,
  userPrompt: promptData.userPrompt,
  viewerName: promptData.viewerName,
  userRoleLabel: promptData.userRoleLabel,
  isDrafting: promptData.isDrafting,
} }];

// ============================================================================
// FORMAT SUCCESSFUL RESPONSE for QC Chat v2.0
// ============================================================================

const claudeResponse = $input.first().json;

// Extract response text from Anthropic Messages API response
// Response format: { content: [{ type: 'text', text: '...' }], ... }
let responseText = '';

if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  // Standard Anthropic Messages API response
  responseText = claudeResponse.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof claudeResponse.text === 'string') {
  responseText = claudeResponse.text;
} else if (typeof claudeResponse.response === 'string') {
  responseText = claudeResponse.response;
} else if (typeof claudeResponse.output === 'string') {
  responseText = claudeResponse.output;
}

if (!responseText) {
  responseText = 'I apologize, but I was unable to generate a response. Please try again.';
}

console.log('=== QC CHAT RESPONSE ===');
console.log('Response length:', responseText.length);
console.log('Model:', claudeResponse.model || 'unknown');
console.log('Stop reason:', claudeResponse.stop_reason || 'unknown');
console.log('Input tokens:', claudeResponse.usage?.input_tokens || 0);
console.log('Output tokens:', claudeResponse.usage?.output_tokens || 0);

return [{ json: {
  response: responseText,
  message: responseText,
  success: true
} }];

// ============================================================================
// ERROR HANDLER — returns a graceful error response
// ============================================================================

const errorData = $input.first().json;

console.error('=== QC CHAT ERROR ===');
console.error('Error:', JSON.stringify(errorData).substring(0, 500));

const errorMessage = 'I apologize, but I encountered an issue processing your request. Please try again in a moment.';

return [{ json: {
  response: errorMessage,
  message: errorMessage,
  success: false,
  error: true
} }];
